mapper.sql:
SELECT ROW_NUMBER() OVER(ORDER BY TO_DATE(A.REG_DTTM, 'YYYYMMDDHH24MISS') DESC) AS "LINE_NO" /* Row Number */ , D.ORGNM AS "ORGNM" /* 기관 I */ , B.ORG_ID AS "ORG_ID" /* 기관 I ID (HIDDEN) */ , C.DEPTNM AS "DEPTNM" /* 학과 I */ , B.DEPT_ID AS "DEPT_ID" /* 학과 I ID (HIDDEN) */ , TO_CHAR(TO_DATE(A.REG_DTTM, 'YYYYMMDDHH24MISS') , 'YYYY.MM.DD HH24:MI') AS "REG_DTTM" /* 일시 */ , B.STDNT_NO AS "STDNT_NO" /* 학번/사번 */ , B.USERNM AS "USERNM" /* 등록자 명 */ , A.RGTR_ID AS "RGTR_ID" /* 등록자 ID (HIDDEN) */ , A.SYS_ERR_PAGENM AS "SYS_ERR_PAGENM" /* 오류페이지 */ , A.SYS_ERR_MSG_ID AS "SYS_ERR_MSG_ID" /* 에러메시지 ID (HIDDEN) */ FROM TB_LMS_SYS_ERR_MSG A JOIN TB_LMS_USER B ON A.RGTR_ID = B.USER_ID JOIN TB_LMS_DEPT C ON B.DEPT_ID = C.DEPT_ID JOIN TB_LMS_ORG D ON B.ORG_ID = D.ORG_ID WHERE 1=1
AND B.ORG_ID = #{orgId}
AND B.DEPT_ID = #{deptId}
AND B.STDNT_NO = #{stdntNo}
AND B.USERNM LIKE '%' || #{usernm} || '%'
